import{_ as i,o as e,c as l,a2 as r}from"./chunks/framework.DIMps2S2.js";const u=JSON.parse('{"title":"Longbridge AI","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"app-guide/lb-ai.md","filePath":"zh-CN/app-guide/lb-ai.md"}'),o={name:"app-guide/lb-ai.md"};function t(d,a,n,h,b,g){return e(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="longbridge-ai" tabindex="-1">Longbridge AI <a class="header-anchor" href="#longbridge-ai" aria-label="Permalink to &quot;Longbridge AI&quot;">​</a></h1><p>LongbridgeAI 是 Longbridge 推出的综合财经智能助理，结合大语言模型与财经数据、资讯及社区内容，帮助用户高效获取财经信息。</p><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h2><p>LongbridgeAI 提供 4 种使用入口：</p><ol><li>IM 对话：在 Longbridge IM 中直接与 LongbridgeAI 对话</li><li>社区 @：在社区帖子或评论中 @ LongbridgeAI，即可触发回复</li><li>文章总结：文章字数超过 300 字时，可一键生成摘要</li><li>持仓日报总结：对持仓日报内容进行智能解读和汇总</li></ol><h2 id="服务范围" tabindex="-1">服务范围 <a class="header-anchor" href="#服务范围" aria-label="Permalink to &quot;服务范围&quot;">​</a></h2><p>LongbridgeAI 专注于财经领域，可协助处理以下需求：</p><ul><li>查找财经信息（股票、市场、宏观数据等）</li><li>追踪特定事件的最新进展</li><li>解释和归因市场或公司相关事件</li></ul><h2 id="不提供的服务" tabindex="-1">不提供的服务 <a class="header-anchor" href="#不提供的服务" aria-label="Permalink to &quot;不提供的服务&quot;">​</a></h2><p>以下需求超出 LongbridgeAI 的服务范围，不予回答：</p><ul><li>选股建议</li><li>投资决策指导</li><li>股市走势预测</li><li>非财经领域问题</li></ul><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><p>为获得更准确的回答，建议：</p><ul><li>问题聚焦于投资和财经领域</li><li>描述尽量具体、简洁、无歧义</li></ul><h2 id="免责声明" tabindex="-1">免责声明 <a class="header-anchor" href="#免责声明" aria-label="Permalink to &quot;免责声明&quot;">​</a></h2><p>LongbridgeAI 提供的内容仅供参考，不构成投资建议。投资有风险，决策前请结合自身情况审慎判断。</p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/app-guide">App 导览</a></li></ul>',18)])])}const s=i(o,[["render",t]]);export{u as __pageData,s as default};
